// src/components/Header/index.jsx

import React from 'react';
import { Link } from 'react-router-dom';
import { useSelector } from 'react-redux';
import Button from '../UI/Button';
import s from './Header.module.css';
import { FaShoppingCart } from 'react-icons/fa'; // Пример иконки корзины (требует установки 'react-icons')
import logoSrc from '../../assets/images/logo.png';

// Установка: npm install react-icons

const Header = () => {
  // Получаем общее количество товаров в корзине
  const cartItemCount = useSelector(state => 
    state.cart.items.reduce((total, item) => total + item.count, 0)
  );

  return (
    <header className={s.header}>
      <div className={s.container}>

        {/* Логотип / Ссылка на Главную */}
        <Link to="/" className={s.logo}>
          <img src={logoSrc} alt="Garden Shop Logo" />
          <span className={s.logoText}>Garden Store</span>
        </Link>

        {/* Навигация */}
        <nav className={s.nav}>
          <Link to="/" className={s.navLink}>Главная</Link>
          <Link to="/categories" className={s.navLink}>Категории</Link>
          <Link to="/products" className={s.navLink}>Все товары</Link>
          {/* Ссылка на товары со скидкой (опционально, может вести на /products с фильтром) */}
          <Link to="/products" className={s.navLink}>Скидки</Link> 
        </nav>

        <div className={s.actions}>
          {/* Кнопка "В каталог" (может быть как Button) */}
          <Link to="/products">
            <Button type="secondary" className={s.catalogButton}>
              В каталог
            </Button>
          </Link>

          {/* Иконка Корзины */}
          <Link to="/cart" className={s.cartLink}>
            <FaShoppingCart className={s.cartIcon} />
            {cartItemCount > 0 && (
              <span className={s.cartCount}>{cartItemCount}</span>
            )}
          </Link>
        </div>

      </div>
    </header>
  );
};

export default Header;
